<?php require __DIR__.'/bootstrap.php'; global $config; $action=$_GET['action'] ?? 'session'; if($_SERVER['REQUEST_METHOD']==='POST' && $action==='login'){ $body=read_json_body(); if(($body['password'] ?? '') !== ($config['admin_password'] ?? '')) out(['ok'=>false,'error'=>'Погрешна лозинка'],401); $_SESSION['fgsm_admin']=true; out(['ok'=>true]); } if($_SERVER['REQUEST_METHOD']==='POST' && $action==='logout'){ session_destroy(); out(['ok'=>true]); } out(['ok'=>true,'authenticated'=>!empty($_SESSION['fgsm_admin'])]);
